from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    triples_by_subject = {}
    for triple in triples:
        if triple.subject not in triples_by_subject:
            triples_by_subject[triple.subject] = []
        triples_by_subject[triple.subject].append(triple)

    # Find main subject (prefer astronaut-related predicates)
    astronaut_predicates = {'occupation', 'birthDate', 'birthPlace', 'birthName', 'deathDate',
                           'deathPlace', 'nationality', 'mission', 'timeInSpace', 'selectedByNasa',
                           'status', 'almaMater', 'awards', 'award', 'alternativeName', 'title',
                           'servedAsChiefOfTheAstronautOfficeIn', 'dateOfRetirement', 'ribbonAward'}

    main_subject = None
    for subject, subject_triples in triples_by_subject.items():
        if any(t.predicate in astronaut_predicates for t in subject_triples):
            main_subject = subject
            break

    if not main_subject:
        main_subject = list(triples_by_subject.keys())[0]

    main_triples = triples_by_subject.get(main_subject, [])
    other_triples = [t for t in triples if t.subject != main_subject]

    # Build sentence fragments
    fragments = []

    for triple in main_triples:
        pred = triple.predicate
        obj = triple.object

        if pred == 'occupation':
            fragments.append(f"{main_subject} was a {obj}")
        elif pred == 'birthDate':
            fragments.append(f"born on {obj}")
        elif pred == 'birthPlace':
            fragments.append(f"born in {obj}")
        elif pred == 'deathDate':
            fragments.append(f"died on {obj}")
        elif pred == 'deathPlace':
            fragments.append(f"died in {obj}")
        elif pred == 'nationality':
            fragments.append(f"who was {obj}")
        elif pred == 'mission':
            fragments.append(f"part of the {obj} mission")
        elif pred == 'timeInSpace':
            fragments.append(f"with {obj} minutes in space")
        elif pred == 'selectedByNasa':
            fragments.append(f"selected by NASA in {obj}")
        elif pred == 'status':
            fragments.append(f"currently {obj}")
        elif pred == 'almaMater':
            fragments.append(f"educated at {obj}")
        elif pred == 'awards':
            fragments.append(f"received {obj} awards")
        elif pred == 'award':
            fragments.append(f"received the {obj}")
        elif pred == 'alternativeName':
            fragments.append(f"also known as {obj}")
        elif pred == 'title':
            fragments.append(f"held the title of {obj}")
        elif pred == 'dateOfRetirement':
            fragments.append(f"retired in {obj}")
        elif pred == 'ribbonAward':
            fragments.append(f"earned the {obj}")
        elif pred == 'deathName':
            fragments.append(f"birth name was {obj}")
        elif pred == 'backupPilot':
            fragments.append(f"backup pilot was {obj}")
        elif pred == 'commander':
            fragments.append(f"commander was {obj}")
        elif pred == 'crewMembers':
            fragments.append(f"crew included {obj}")
        elif pred == 'operator':
            fragments.append(f"operated by {obj}")
        elif pred == 'cosparId':
            fragments.append(f"with COSPAR ID {obj}")

    # Build coherent sentence
    if not fragments:
        return f"{main_subject} has information in the database."

    sentence = fragments[0]
    for fragment in fragments[1:]:
        if fragment.startswith("born") or fragment.startswith("died") or fragment.startswith("who"):
            sentence += ", " + fragment
        else:
            sentence += ", and " + fragment

    # Add related triples as additional clauses
    for triple in other_triples:
        if triple.predicate == 'operator':
            sentence += f", which was operated by {triple.object}"
        elif triple.predicate == 'commander':
            sentence += f", with {triple.object} as commander"
        elif triple.predicate == 'backupPilot':
            sentence += f", with {triple.object} as backup pilot"
        elif triple.predicate == 'crewMembers':
            sentence += f", including crew member {triple.object}"

    return sentence + "."

# EVOLVE-BLOCK-END

